using SkiaSharp;

Console.WriteLine("Test 1: Creating bitmap and drawing...");
using var bitmap = new SKBitmap(400, 400);
using var canvas = new SKCanvas(bitmap);
canvas.Clear(SKColors.White);
using var paint = new SKPaint();
paint.Color = SKColors.Red;
paint.Style = SKPaintStyle.Fill;
canvas.DrawRect(new SKRect(50, 50, 200, 200), paint);
paint.Color = SKColors.Blue;
canvas.DrawCircle(300, 300, 80, paint);
canvas.Flush();
var redPixel = bitmap.GetPixel(100, 100);
var bluePixel = bitmap.GetPixel(300, 300);
var whitePixel = bitmap.GetPixel(10, 10);
Console.WriteLine($"Red pixel (100,100): R={redPixel.Red} G={redPixel.Green} B={redPixel.Blue} A={redPixel.Alpha}");
Console.WriteLine($"Blue pixel (300,300): R={bluePixel.Red} G={bluePixel.Green} B={bluePixel.Blue} A={bluePixel.Alpha}");
Console.WriteLine($"White pixel (10,10): R={whitePixel.Red} G={whitePixel.Green} B={whitePixel.Blue} A={whitePixel.Alpha}");
Console.WriteLine("\nTest 2: Encoding image to PNG...");
using var image = SKImage.FromBitmap(bitmap);
if (image == null) { Console.WriteLine("ERROR: SKImage.FromBitmap returned null!"); return 1; }
using var data = image.Encode(SKEncodedImageFormat.Png, 100);
if (data == null) { Console.WriteLine("ERROR: image.Encode returned null!"); return 1; }
Console.WriteLine($"Encoded PNG size: {data.Size} bytes");
Console.WriteLine("\nTest 3: Decoding image back...");
using var decoded = SKImage.FromEncodedData(data);
if (decoded == null) { Console.WriteLine("ERROR: SKImage.FromEncodedData returned null!"); return 1; }
Console.WriteLine($"Decoded image: {decoded.Width}x{decoded.Height}");
using var decodedBitmap = SKBitmap.FromImage(decoded);
var dRedPixel = decodedBitmap.GetPixel(100, 100);
Console.WriteLine($"Decoded red pixel (100,100): R={dRedPixel.Red} G={dRedPixel.Green} B={dRedPixel.Blue} A={dRedPixel.Alpha}");
bool redOk = dRedPixel.Red > 200 && dRedPixel.Green < 50 && dRedPixel.Blue < 50;
bool blueOk = bluePixel.Red < 50 && bluePixel.Green < 50 && bluePixel.Blue > 200;
if (redOk && blueOk) Console.WriteLine("\nSUCCESS: test completed - images appear correctly");
else Console.WriteLine($"\nFAILURE: pixel colors unexpected (red ok: {redOk}, blue ok: {blueOk})");
return 0;
